function runGenerator(genFn) {
  const gen = genFn();

  function step(value) {
    const result = gen.next(value);
    if (!result.done) {
      result.value.then(step);
    }
  }

  step();
}

// Generator-based async function
function* genExample() {
  console.log('Start');
  yield wait(1000);
  console.log('1 second later');
}

runGenerator(genExample);

